record.field:
for rec in records:
    if rec.x_intake_phase == 'prescreening' and rec.x_chairman_decision == 'pending':
        rec.write({
            'x_chairman_decision': 'approved',
            'x_intake_phase': 'pooling',
        })

for rec in records:
    if rec.x_intake_phase != 'converted':
        rec.write({
            'x_chairman_decision': 'on_hold',
            'x_intake_phase': 'pooling',
        })

for rec in records:
    if rec.x_intake_phase != 'converted':
        rec.write({
            'x_chairman_decision': 'rejected',
            'x_intake_phase': 'pooling',
        })
